import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

function App() {
  // Estados do sistema
  const [etapa, setEtapa] = useState('login'); // 'login' ou 'retirada'
  const [codigo, setCodigo] = useState("");
  const [usuario, setUsuario] = useState(null);
  const [mensagem, setMensagem] = useState("Aguardando leitura do crachá...");
  const [erro, setErro] = useState(false);

  // Referência para manter o foco no input automaticamente
  const inputRef = useRef(null);

  useEffect(() => {
    // Garante que o campo de texto sempre esteja selecionado para o leitor
    inputRef.current?.focus();
  }, [etapa]);

  const handleKeyPress = async (e) => {
    if (e.key === 'Enter') {
      const valorLido = codigo.trim();
      if (!valorLido) return;

      if (etapa === 'login') {
        await realizarLogin(valorLido);
      } else {
        await realizarRetirada(valorLido);
      }
      setCodigo(""); // Limpa o campo para o próximo bip
    }
  };

  const realizarLogin = async (codBarras) => {
    setMensagem("Verificando crachá...");
    setErro(false);

    try {
      // Conecta com seu Backend na porta 3001
      const response = await axios.post('http://localhost:3001/login', { codBarras });
      
      if (response.data) {
        setUsuario(response.data);
        setEtapa('retirada');
        setMensagem(`✅ Olá, ${response.data.nome}! Agora bipe a ferramenta.`);
      }
    } catch (err) {
      setErro(true);
      setMensagem("❌ Crachá não cadastrado no sistema.");
    }
  };

  const realizarRetirada = async (ferramentacod) => {
    setMensagem("Registrando retirada...");
    setErro(false);

    try {
      const response = await axios.post('http://localhost:3001/emprestimo/retirada', {
        usuarioId: usuario.id,
        ferramentacod: ferramentacod
      });

      setMensagem(`🎉 Sucesso! ${response.data}`);
      
      // Volta para a tela de login após 3 segundos para o próximo funcionário
      setTimeout(() => {
        setEtapa('login');
        setUsuario(null);
        setMensagem("Aguardando leitura do crachá...");
      }, 3000);

    } catch (err) {
      setErro(true);
      setMensagem("❌ Erro: Ferramenta não encontrada ou já em uso.");
    }
  };

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <img src="/logo-tsea.png" alt="Logo TSEA" style={styles.logo} />
        <h1 style={styles.title}>TSEA - Rastreabilidade de Ferramentas</h1>
      </header>

      <main style={styles.card}>
        <div style={{ ...styles.statusBox, backgroundColor: erro ? '#ffebee' : '#e3f2fd' }}>
          <h2 style={{ color: erro ? '#c62828' : '#0d47a1' }}>{mensagem}</h2>
        </div>

        {usuario && (
          <div style={styles.userInfo}>
            <p><strong>Funcionário:</strong> {usuario.nome}</p>
            <p><strong>Matrícula:</strong> {usuario.id}</p>
          </div>
        )}

        <input
          ref={inputRef}
          type="text"
          value={codigo}
          onChange={(e) => setCodigo(e.target.value)}
          onKeyDown={handleKeyPress}
          placeholder={etapa === 'login' ? "Bipe o Crachá" : "Bipe a Ferramenta"}
          style={styles.input}
        />

        <p style={styles.hint}>
          {etapa === 'login' 
            ? "Passe o scanner no código de barras do seu crachá." 
            : "Passe o scanner no código de barras da ferramenta escolhida."}
        </p>
      </main>

      <footer style={styles.footer}>
        Equipe: SSS - SuperSonicSpeed | SENAI 4.0
      </footer>
    </div>
  );
}

// Estilos simples para deixar o visual limpo (como a imagem que você mandou)
const styles = {
  container: {
    fontFamily: 'Segoe UI, Tahoma, Geneva, Verdana, sans-serif',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    minHeight: '100vh',
    backgroundColor: '#f0f2f5',
    color: '#333',
  },
  header: {
    marginTop: '40px',
    textAlign: 'center',
  },
  logo: {
    width: '180px',
    marginBottom: '10px',
  },
  title: {
    color: '#002d62',
    fontSize: '24px',
  },
  card: {
    backgroundColor: '#fff',
    padding: '40px',
    borderRadius: '15px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.1)',
    textAlign: 'center',
    marginTop: '20px',
    width: '450px',
  },
  statusBox: {
    padding: '15px',
    borderRadius: '8px',
    marginBottom: '20px',
  },
  input: {
    padding: '15px',
    fontSize: '18px',
    width: '80%',
    borderRadius: '5px',
    border: '2px solid #0055ff',
    textAlign: 'center',
    outline: 'none',
  },
  userInfo: {
    textAlign: 'left',
    backgroundColor: '#f9f9f9',
    padding: '10px',
    borderRadius: '5px',
    marginBottom: '20px',
    fontSize: '14px',
  },
  hint: {
    marginTop: '15px',
    fontSize: '12px',
    color: '#777',
  },
  footer: {
    marginTop: 'auto',
    marginBottom: '20px',
    fontSize: '12px',
    color: '#aaa',
  }
};

export default App;
